#include <bits/stdc++.h>
using namespace std;
struct Node{
    int to,val;
};
int n,m,a[100005];
bool mark[100005];
vector<Node> g[100005];
void bfs(){
    queue<int> b;
    b.push(1),mark[1]=1;
    while(b.size()){
        int u=b.front(),len=g[u].size();
        b.pop();
        for(int i=0;i<len;i++){
            int v=g[u][i].to;
            if(!mark[v])
                mark[v]=1,a[v]=a[u]^g[u][i].val,b.push(v);
        }
    }
}
int main(){
    cin>>n;
    for(int i=1;i<n;i++){
        int u,v,w;
        cin>>u>>v>>w;
        g[u].push_back({v,w});
        g[v].push_back({u,w});
    }
    bfs();
    cin>>m;
    while(m--){
        int u,v;
        cin>>u>>v;
        cout<<(a[u]^a[v])<<'\n';
    }
    return 0;
}
